import { formatDate, getDuration } from '../../utils.js';

function createOfferTemplate({title, price}){
  return `
    <li class="event__offer">
      <span class="event__offer-title">${title}</span>
      &plus;&euro;&nbsp;
      <span class="event__offer-price">${price}</span>
    </li>
    `;
}

export function createPointTemplate (point, offers, destinations) {
  const {type, date_from, date_to, is_favorite, base_price} = point;
  const typeOffers = offers.find((item) => item.type === point.type).offers;
  const pointOffers = typeOffers.filter((typeOffer) => point.offers.includes(typeOffer.id));
  const pointDestination = destinations.find((dest) => dest.id === point.destination);

  return `
            <li class="trip-events__item">
              <div class="event">
                <time class="event__date" datetime=${formatDate(date_from, 'full-date')}>${formatDate(date_from, 'custom')}</time>
                <div class="event__type">
                  <img class="event__type-icon" width="42" height="42" src="img/icons/${type.toLowerCase()}.png" alt="Event type icon">
                </div>
                <h3 class="event__title">${type} ${pointDestination.name}</h3>
                <div class="event__schedule">
                  <p class="event__time">
                    <time class="event__start-time" datetime=${formatDate(date_from, 'date-time')}>${formatDate(date_from, 'time')}</time>
                    &mdash;
                    <time class="event__end-time" datetime=${formatDate(date_to, 'date-time')}>${formatDate(date_to, 'time')}</time>
                  </p>
                  <p class="event__duration">${getDuration(date_from, date_to)}</p>
                </div>
                <p class="event__price">
                  &euro;&nbsp;<span class="event__price-value">${base_price}</span>
                </p>
                <h4 class="visually-hidden">Offers:</h4>
                <ul class="event__selected-offers">
                  ${pointOffers.map((offer) => createOfferTemplate(offer)).join('')}
                </ul>
                <button class="event__favorite-btn ${is_favorite ? 'event__favorite-btn--active' : ''}" type="button">
                  <span class="visually-hidden">Add to favorite</span>
                  <svg class="event__favorite-icon" width="28" height="28" viewBox="0 0 28 28">
                    <path d="M14 21l-8.22899 4.3262 1.57159-9.1631L.685209 9.67376 9.8855 8.33688 14 0l4.1145 8.33688 9.2003 1.33688-6.6574 6.48934 1.5716 9.1631L14 21z"/>
                  </svg>
                </button>
                <button class="event__rollup-btn" type="button">
                  <span class="visually-hidden">Open event</span>
                </button>
              </div>
            </li>`;
}
